static     public boolean isPower(int x, int y) {
        // If x is 1, y must also be 1 for it to be a power of x.
        if (x == 1) {
            return (y == 1);
        }
        // Start with the 0th power, which is 1.
        // Use long to prevent overflow during multiplication.
        long pow = 1;
        // Keep multiplying by x until pow is greater than or equal to y.
        while (pow < y) {
            pow *= x;
        }
        // If pow is exactly y, then y is a power of x.
        return (pow == y);
    }

