        // Base case: nC0 is always 1
        C[0] = 1;
        // Build the table using Pascal's Identity: C(n, k) = C(n-1, k) + C(n-1, k-1)
        for (int i = 1; i <= n; i++) {
            // We fill the C[] array from right to left.
            // This is crucial because when computing C[j], we need the value
            // of C[j-1] from the previous row (i-1). Iterating backwards
            // ensures C[j-1] has not been updated for the current row i yet.
            for (int j = Math.min(i, r); j > 0; j--) {
                C[j] = (C[j] + C[j - 1]) % p;
            }
        }
        return C[r];
    }

